sections.example:
const nums = [10, 20, 30, 40];
console.log(nums[0]);       // 10
console.log(nums.at(-1));   // 40 (last element)
console.log(nums.length);   // 4

const zeros = new Array(3).fill(0);
console.log(zeros);         // [0, 0, 0]

const stack = [1, 2, 3];
stack.push(4);         // [1, 2, 3, 4]
const last = stack.pop(); // 4, stack is [1, 2, 3]

const queue = [1, 2, 3];
queue.push(4);             // [1, 2, 3, 4]
const first = queue.shift(); // 1, queue is [2, 3, 4]

