const nums = [10, 20, 30];

// Classic for — when you need index
for (let i = 0; i < nums.length; i++) {
  // use nums[i]
}

// for...of — clean value iteration
for (const val of nums) {
  // use val
}

// forEach — callback style
nums.forEach((val, i) => {
  // use val and i
});

